			identifier: id,
			tokenableId: dbRow.tokenable_id,
			type: dbRow.type,
			prefix: this.prefix,
			secret: transientToken.secret,
			name: dbRow.name,
			hash: dbRow.hash,
			abilities: JSON.parse(dbRow.abilities),
			createdAt: dbRow.created_at,
			updatedAt: dbRow.updated_at,
