/**
* Configures access tokens guard for authentication
*
* @param config - Configuration object containing the user provider
*
* @example
* const guard = tokensGuard({
*   provider: tokensUserProvider({
*     model: () => import('#models/user'),
*     tokens: 'accessTokens'
*   })
* })
*/
